export const getGetDownloadsOverTimeUrl = (params?: GetDownloadsOverTimeParams,) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {

    if (value !== undefined) {
      normalizedParams.append(key, value === null ? 'null' : value.toString())
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0 ? `/api/admin/analytics/downloads-over-time?${stringifiedParams}` : `/api/admin/analytics/downloads-over-time`
}

